import { PremblyPass } from 'prembly-pass';

const apiKey = import.meta.env.VITE_PREMBLY_API_KEY;
const appId = 'test_app_id';
const configId = 'test_config_id';

const statusDiv = document.getElementById('status');

const prembly = new PremblyPass({
  app_id: appId,
  x_api_key: apiKey,
  environment: 'test',
  sandbox_url: 'https://api.prembly.com'
});

document.getElementById('launch-widget').addEventListener('click', () => {
  const userRef = `user_${Math.random().toString(36).substring(7)}`;

  statusDiv.innerText = 'Initializing widget...';

  prembly.launch({
    config_id: configId,
    user_ref: userRef,
    onSuccess: (data) => {
      console.log('Verification Success:', data);
      statusDiv.innerText = 'Verification Successful! Check console for details.';
      statusDiv.style.color = 'green';
    },
    onError: (error) => {
      console.error('Verification Error:', error);
      statusDiv.innerText = `Verification Error: ${error.message || 'Unknown error'}`;
      statusDiv.style.color = 'red';
    }
  });
});

